const orders = $input.all().map(i => i.json);

const escalations = orders.map(o => ({
  ...o,
  escalation_level: o.priority === 'high' ? 'CRITICAL' : 'WARNING',
  escalation_reason: getEscalationReason(o),
  escalated_at: new Date().toISOString()
}));

function getEscalationReason(o) {
  if (o.status === 'DISPATCH_FAILED') return 'Carrier API failure - needs manual intervention';
  if (o.status === 'BACKORDERED') return `Backorder unresolved for ${Math.round(o.hours_in_status)}h`;
  return `Order stuck in ${o.status} for ${Math.round(o.hours_in_status)}h (SLA breach)`;
}

return escalations.map(e => ({ json: e }));

// Summary report for ops dashboard
const items = $input.all().map(i => i.json);
const critical = items.filter(i => i.escalation_level === 'CRITICAL').length;
const warning = items.filter(i => i.escalation_level === 'WARNING').length;
return [{ json: { total: items.length, critical, warning, run_at: new Date().toISOString() } }];
